    <script>
    async function fetchCourses() {
      const response = await fetch('https://nanoschool.in/courses-data/all_courses.json');
      const courses = await response.json();
      
      const randomCourses = [];
      while(randomCourses.length < 5) {
        const randomIndex = Math.floor(Math.random() * courses.length);
        const course = courses[randomIndex];
        if (!randomCourses.includes(course)) {
          randomCourses.push(course);
        }
      }

      const randomCoursesContainer = document.getElementById('random-courses');
      randomCoursesContainer.innerHTML = randomCourses.map(course => `
        <div class="benefit-item">
          <h3 class="font-semibold text-gray-900 mb-1">${course.title}</h3>
          <p class="text-sm text-gray-600">${course.description}</p>
          <a href="${course.link}" class="text-blue-600 hover:underline">Learn More</a>
        </div>
      `).join('');
    }

    // Call the function to fetch courses on page load
    fetchCourses()
    function populateSidebarCategories() {
      const container = document.getElementById('categories-section');
      if (!container) return;
      try {
        let html = '<h3>Explore Related Categories</h3>';
        const visibleCount = window.innerWidth < 768 ? 3 : sidebarCategories.length;
        sidebarCategories.slice(0, visibleCount).forEach(category => {
          html += `
            <div class="category-item" role="listitem">
              <i class="${category.icon}" aria-hidden="true"></i>
              <a href="${category.link}" target="_blank" rel="noopener noreferrer" aria-label="Learn more about ${category.name}">${category.name}</a>
              <p class="text-xs text-gray-500 ml-auto">${category.description}</p>
            </div>
          `;
        });
        if (visibleCount < sidebarCategories.length) {
          html += '<div class="show-more"><button id="show-more-categories" aria-expanded="false">Show More Categories</button></div>';
        }
        container.innerHTML = html;
        // Show More Functionality
        document.getElementById('show-more-categories')?.addEventListener('click', (e) => {
          e.target.textContent = 'Show Less';
          // Add remaining categories (simplified)
          container.innerHTML += sidebarCategories.slice(visibleCount).map(cat => `
            <div class="category-item" role="listitem">
              <i class="${cat.icon}" aria-hidden="true"></i>
              <a href="${cat.link}" target="_blank" rel="noopener noreferrer" aria-label="Learn more about ${cat.name}">${cat.name}</a>
              <p class="text-xs text-gray-500 ml-auto">${cat.description}</p>
            </div>
          `).join('');
          e.target.remove();
        });
      } catch (error) {
        console.error('Error populating categories:', error);
        container.innerHTML = '<p class="text-center text-gray-500">Categories loading...</p>';
      }
    }
    // Enhanced JS with Error Handling and Accessibility
    document.addEventListener('DOMContentLoaded', () => {
      populateSidebarCategories();
      // Video Overlay
      const videoOverlay = document.querySelector('.video-overlay');
      if (videoOverlay) {
        videoOverlay.addEventListener('click', () => {
          const iframe = videoOverlay.parentElement.querySelector('iframe');
          iframe.src += '&autoplay=1';
          videoOverlay.style.display = 'none';
        });
        videoOverlay.addEventListener('keydown', (e) => {
          if (e.key === 'Enter' || e.key === ' ') {
            e.preventDefault();
            videoOverlay.click();
          }
        });
      }
      // Navigation
      const navLinks = document.querySelectorAll('.nav-menu a');
      const sections = document.querySelectorAll('section[id]');
      navLinks.forEach(link => {
        link.addEventListener('click', (e) => {
          e.preventDefault();
          const targetId = link.getAttribute('href').substring(1);
          const targetSection = document.getElementById(targetId) || document.querySelector(`[id="${targetId}"]`);
          if (targetSection) {
            targetSection.scrollIntoView({ behavior: 'smooth' });
            navLinks.forEach(l => {
              l.removeAttribute('aria-current');
              l.classList.remove('active');
            });
            link.setAttribute('aria-current', 'page');
            link.classList.add('active');
          }
        });
      });
      // Throttled Scroll Observer for Active Nav
      let ticking = false;
      function updateActiveNav() {
        if (ticking) return;
        ticking = true;
        requestAnimationFrame(() => {
          const scrollPos = window.scrollY + window.innerHeight / 2;
          let current = 'hero'; // Default
          sections.forEach(section => {
            if (scrollPos >= section.offsetTop && scrollPos < section.offsetTop + section.offsetHeight) {
              current = section.id;
            }
          });
          navLinks.forEach(link => {
            link.removeAttribute('aria-current');
            link.classList.remove('active');
            if (link.getAttribute('href') === `#${current}`) {
              link.setAttribute('aria-current', 'page');
              link.classList.add('active');
            }
          });
          ticking = false;
        });
      }
      window.addEventListener('scroll', updateActiveNav);
      // Skills Progress Bars
      document.querySelectorAll('.skill-fill').forEach(fill => {
        setTimeout(() => fill.style.width = fill.dataset.width, 300);
      });
      // Syllabus Accordion with ARIA and Toggle All
      const syllabusHeaders = document.querySelectorAll('.accordion-header');
      syllabusHeaders.forEach(h => {
        h.addEventListener('click', toggleAccordion);
        h.addEventListener('keydown', (e) => {
          if (e.key === 'Enter' || e.key === ' ') {
            e.preventDefault();
            toggleAccordion.call(h);
          }
        });
      });
      function toggleAccordion() {
        const content = document.getElementById(this.dataset.accordion);
        const isOpen = content.getAttribute('aria-hidden') === 'false';
        document.querySelectorAll('.accordion-content').forEach(c => {
          c.setAttribute('aria-hidden', 'true');
          c.parentElement.querySelector('.accordion-header').setAttribute('aria-expanded', 'false');
        });
        if (!isOpen) {
          content.setAttribute('aria-hidden', 'false');
          this.setAttribute('aria-expanded', 'true');
          this.querySelector('i').style.transform = 'rotate(180deg)';
        }
      }
      document.getElementById('toggle-syllabus').addEventListener('click', () => {
        const isExpanded = document.getElementById('toggle-syllabus').getAttribute('aria-expanded') === 'true';
        syllabusHeaders.forEach(h => {
          h.setAttribute('aria-expanded', !isExpanded);
          const content = document.getElementById(h.dataset.accordion);
          content.setAttribute('aria-hidden', isExpanded ? 'false' : 'true');
          h.querySelector('i').style.transform = !isExpanded ? 'rotate(180deg)' : 'rotate(0deg)';
        });
        document.getElementById('toggle-syllabus').textContent = isExpanded ? 'Collapse All' : 'Expand All';
        document.getElementById('toggle-syllabus').setAttribute('aria-expanded', !isExpanded);
      });
      // Enhanced FAQ with Search and ARIA
      const faqQuestions = document.querySelectorAll('.faq-question');
      faqQuestions.forEach(q => {
        q.addEventListener('click', toggleFaq);
        q.addEventListener('keydown', (e) => {
          if (e.key === 'Enter' || e.key === ' ') {
            e.preventDefault();
            toggleFaq.call(q);
          }
        });
      });
      function toggleFaq() {
        const answer = document.getElementById(this.dataset.faq);
        const isOpen = answer.getAttribute('aria-hidden') === 'false';
        document.querySelectorAll('.faq-answer').forEach(a => a.setAttribute('aria-hidden', 'true'));
        document.querySelectorAll('.faq-question').forEach(qq => {
          qq.setAttribute('aria-expanded', 'false');
          qq.classList.remove('active');
        });
        if (!isOpen) {
          answer.setAttribute('aria-hidden', 'false');
          this.setAttribute('aria-expanded', 'true');
          this.classList.add('active');
        }
      }
      // FAQ Search Functionality
      const searchInput = document.getElementById('faq-search-input');
      const faqList = document.getElementById('faq-list');
      const noResults = document.getElementById('faq-no-results');
      searchInput.addEventListener('input', (e) => {
        const term = e.target.value.toLowerCase();
        let visibleCount = 0;
        faqList.querySelectorAll('.faq-item').forEach(item => {
          const question = item.querySelector('.faq-question span').textContent.toLowerCase();
          if (question.includes(term) || term === '') {
            item.style.display = 'block';
            visibleCount++;
          } else {
            item.style.display = 'none';
          }
        });
        noResults.style.display = visibleCount === 0 && term !== '' ? 'block' : 'none';
      });
      // Spots Counter with ARIA Live
      let spots = 49;
      const counter = document.getElementById('spots-counter');
      setInterval(() => {
        if (spots > 20) {
          spots--;
          counter.textContent = `${spots} left`;
          counter.setAttribute('aria-label', `${spots} spots remaining in cohort`);
        }
      }, 10000);
      // Back to Top
      window.addEventListener('scroll', () => {
        document.getElementById('backToTop').classList.toggle('show', window.scrollY > 400);
      });
      document.getElementById('backToTop').addEventListener('click', () => window.scrollTo({ top: 0, behavior: 'smooth' }));
      // Lazy Loading Observer
      if ('IntersectionObserver' in window) {
        const obs = new IntersectionObserver(entries => {
          entries.forEach(e => {
            if (e.isIntersecting) {
              const img = e.target;
              img.src = img.dataset.src || img.src;
              img.classList.remove('lazy');
              obs.unobserve(img);
            }
          });
        }, { rootMargin: '50px' });
        document.querySelectorAll('img[loading="lazy"]').forEach(img => obs.observe(img));
      }
      // Focus Management for Modals/Overlays (if added later)
      // Example: Trap focus in modals – implement as needed
    });
  </script>

